    public static ShopTemplate getShopTemplate(int id) {
        for (int i = 0; i < shop.length; i++) {
            if (shop[i].id == id) {
                return shop[i];
            }
        }

        return null;
    }

    public static boolean canAddShopGemStack(Char player, int idGem, int amount, boolean lock) {
        int current = lock ? player.listGemitemLock[idGem] : Math.max(0, player.listGemitem[idGem] - player.listGemitemSell[idGem]);
        if (current + amount <= MAX_SHOP_GEM_STACK) {
            return true;
        }

        String itemName = "vật phẩm";
        if (idGem >= 0 && idGem < gemTemplate.length && gemTemplate[idGem] != null) {
            itemName = gemTemplate[idGem].name;
        }
        player.sendMessage(MessageCreator.createServerAlertMessage(
                "Chỉ có thể giữ tối đa " + MAX_SHOP_GEM_STACK + " " + itemName + " trong 1 stack. Bạn đang có " + current + ", hãy dùng bớt trước khi mua tiếp.",
                ""));
        return false;
    }

    public static int getIndexShopTemplate(int id) {
        for (int i = 0; i < shop.length; i++) {
            if (shop[i].id == id) {
                return i;
            }
        }

        return -1;
    }

