    public static GemItem dropGemTuBinh(int level) {
        if (level < 40) {
            return null;
        } else {
            int index = 0;
            if (level >= 40 && level < 50) {
                index = 0;
            } else if (level >= 50 && level < 60) {
                index = 1;
            } else if (level >= 60 && level < 70) {
                index = 2;
            } else if (level >= 70 && level < 80) {
                index = 3;
            } else if (level >= 80) {
                index = 3;
            }

            int[][] id = new int[][]{
                {159, 160, 161, 162, 163, 164, 165, 166, 167, 168, 169, 170, 171, 172, 173, 174},
                {179, 180, 181, 182, 183, 184, 185, 186, 187, 188, 189, 190, 191, 192, 193, 194},
                {195, 196, 197, 198, 199, 200, 201, 202, 203, 204, 205, 206, 207, 208, 209, 210},
                {211, 212, 213, 214, 215, 216, 217, 218, 219, 220, 221, 222, 223, 224, 225, 226}
            };
            return new GemItem(id[index][r.nextInt(id[index].length)]);
        }
    }

    public static GemItem dropGemItem(int start, int idTpMonster, boolean isboss) {
        int var7 = 12;
        GemItem gem = null;
        if (idTpMonster != 84 && idTpMonster != 90 && !isboss) {
            int type = r.nextInt(5);
            int percent = 0;
            int startIndex = 0;
            switch (type) {
                case 0:
                    int var12 = 12;
                    percent = r.nextInt(1000);
                    if (percent < 5) {
                        var12 = 24;
                    } else if (percent < 20) {
                        var12 = 20;
                    } else if (percent < 50) {
                        var12 = 16;
                    }

                    gem = new GemItem(r.nextInt(4) + var12);
                    break;
                case 1:
                    int var11 = 28;
                    gem = new GemItem(r.nextInt(6) + var11);
                    break;
                case 2:
                    int var10 = 34;
                    percent = r.nextInt(1000);
                    if (percent < 5) {
                        var10 = 52;
                    } else if (percent < 30) {
                        var10 = 46;
                    } else if (percent < 50) {
                        var10 = 40;
                    }

                    gem = new GemItem(r.nextInt(6) + var10);
                    break;
                case 3:
                    gem = new GemItem(r.nextInt(2) == 0 ? 58 : 59);
                    break;
                case 4:
                    gem = new GemItem(229);
            }
        }

        if (gem != null) {
            gem.cat = 6;
        }

        return gem;
    }

