    public void doSetBangLan(Char p) {
        Vector<LiveActor> ac = new Vector();

        for (Monster mt : (this.monsters.get(p.inCountry)).values()) {
            if (!mt.isDead && inRangeActor(p, mt, 120)) {
                ac.add(mt);
                if (ac.size() == 5) {
                    p.setBangLan(ac);
                    break;
                }
            }
        }

        this.doSetDocLan(p);
    }

    public void doSetDocLan(Char p) {
        Vector<LiveActor> ac = new Vector();

        for (Monster mt : (this.monsters.get(p.inCountry)).values()) {
            if (!mt.isDead && inRangeActor(p, mt, 120)) {
                ac.add(mt);
                if (ac.size() == 5) {
                    p.setDocLan(ac);
                    break;
                }
            }
        }
    }

