    public void doRequestMonterInfo(Char p, Message message) throws IOException {
        DataInputStream dis = message.dis;
        short id = dis.readShort();
        Monster monster = this.getMonster(id, p.mapID != 225 && p.mapID != 226 ? p.inCountry : p.idWedding, p.region);
        if (monster == null) {
            boolean die = true;

            try {
                Monster mons = (Monster) MonsterVantieu.HAS_ALL_MONSTER_VANTIEU.get(id);
                if (mons != null && mons.id == id && !mons.isFinish() && p.map.equals(mons.map)) {
                    monster = mons;
                    die = false;
                }

                if (die) {
                    Message m = new Message(90);
                    m.dos.writeShort(id);
                    m.dos.writeByte(1);
                    p.sendMessage(m);
                }
            } catch (Exception var9) {
                var9.printStackTrace();
            }

            if (die) {
                return;
            }
        }

        if (p.map.equals(monster.map) && (p.near(monster, p.rangeAddMonster[0]) || monster.isBoss() || monster.isCongThanh())) {
            Message m = new Message(7);
            m.dos.writeShort(monster.id);
            m.dos.writeByte(monster.getType());
            m.dos.writeShort(monster.x);
            m.dos.writeShort(monster.y);
            m.dos.writeInt(monster.hp);
            m.dos.writeByte(monster.level);
            m.dos.writeByte(monster.he);
            m.dos.writeInt(monster.maxhp);
            m.dos.writeInt(monster.getTimeReborn());
            p.sendMessage(m);
        }
    }

    private void doRequestItemInfo(Char p, Message message) throws IOException {
        try {
            DataInputStream dis = message.dis;
            short id = dis.readShort();
            short idChar = p.id;

            try {
                idChar = dis.readShort();
            } catch (Exception var15) {
            }

            Char pp = null;
            if (idChar == p.id) {
                pp = p;
            } else {
                pp = this.getChar(idChar);
            }

            boolean isWearing = false;
            if (pp != null) {
                Item[] wItems = pp.getArrayCharWearing();
                Item e = null;

                for (int i = 0; i < wItems.length; i++) {
                    Item e1 = wItems[i];
                    if (e1 != null && e1.id == id) {
                        e = e1;
                        isWearing = true;
                        break;
                    }
                }

                if (e == null) {
                    for (Item e1 : pp.iItems) {
                        if (e1.id == id) {
                            e = e1;
                            break;
                        }
                    }
                }

                if (e == null) {
                    for (Item e1x : pp.tItems) {
                        if (e1x.id == id) {
                            e = e1x;
                            break;
                        }
                    }
                }

                if (e == null) {
                    for (Item e1xx : pp.rItems) {
                        if (e1xx.id == id) {
                            e = e1xx;
                            break;
                        }
                    }
                }

                if (e == null) {
                    for (Item e1xxx : pp.bItem) {
                        if (e1xxx.id == id) {
                            e = e1xxx;
                            break;
                        }
                    }
                }

                if (e == null) {
                    for (Item e1xxxx : pp.awItems) {
                        if (e1xxxx.id == id) {
                            e = e1xxxx;
                            break;
                        }
                    }
                }

                if (e != null) {
                    Message m = new Message(21);
                    m.dos.writeShort(e.id);
                    m.dos.writeShort(e.durable);
                    m.dos.writeByte(e.clazz);
                    m.dos.writeShort(e.getMinuteLoan(true));
                    Vector<InfoItemAttribute> allAtb = e.getInfoAtbItem();
                    m.dos.writeByte(allAtb.size());

                    for (byte j = 0; j < allAtb.size(); j++) {
                        InfoItemAttribute info = (InfoItemAttribute) allAtb.get(j);
                        int x = info.value;
                        if (isWearing) {
                            if (info.id == 66) {
                                x *= p.getXSetLan(0);
                                x += info.value * p.getPCXbangSetDocLuaLan() / 100;
                            } else if (info.id == 67) {
                                x *= p.getXDocLan(0);
                                x += info.value * p.getPCXbangSetDocLuaLan() / 100;
                            } else if (info.id == 68) {
                                x *= p.getXBangLan(0);
                                x += info.value * p.getPCXbangSetDocLuaLan() / 100;
                            } else if (info.id == 89) {
                                x *= p.getXLuaLan(0);
                                x += info.value * p.getPCXbangSetDocLuaLan() / 100;
                            }
                        }

                        m.dos.writeByte(info.id);
                        m.dos.writeShort(x);
                    }

                    m.dos.writeByte(e.plus);
                    m.dos.writeByte(e.lock);
                    p.sendMessage(m);
                    m.cleanup();
                    if (p.id != pp.id) {
                        p.sendMessage(MessageCreator.createCharInventoryMessage(p, 1));
                    }
                }
            }
        } catch (Exception var16) {
            var16.printStackTrace();
        }
    }

