    private Item createItemLoan(Char player, int clazz, int lv) {
        Item item = null;
        int[][] idTemplate = new int[][]{{214, 223}, {224, 233}, {234, 243}, {244, 253}, {254, 263}};
        int id = 0;
        if (id < 26) {
            id = 0;
        } else {
            int[] mlv = new int[]{21, 26, 31, 36, 41, 46, 51, 56, 61, 66};

            for (int i = 0; i < 10; i++) {
                if (mlv[i] > lv) {
                    id = i - 1;
                    break;
                }
            }
        }

        ItemTemplates template = (ItemTemplates) ((Hashtable) itemTemplates.get(0)).get(idTemplate[clazz][0] + id);
        Item newItem = new Item(template, false, template.clazz, template.clazz, idTemplate[clazz][0] + id);
        newItem.id = player.getIDItem();
        newItem.owner = player.charDBID;
        newItem.level = newItem.getTemplate().level;
        player.iItems.add(newItem);
        newItem.clazz = template.clazz;
        if (template.id > 213) {
            newItem.timeLoan = System.currentTimeMillis();
            newItem.minuteExist = template.ndayLoan;
        }

        player.sendMessage(MessageCreator.createMsgChat(player.id, "Chúc mừng, bạn vừa nhận được " + newItem.getTemplate().name));
        return item;
    }

    private void doRideHorse(Char player, int type) {
        if (player.rideHorse <= 0) {
            if (type == 30) {
                player.rideHorse = 1;
                player.idImgHorse = 0;
                player.maxhp += 700;
                player.maxmp += 700;
                player.speed = 6;
                player.xichtho_thienlyma = 1;
            } else if (type == 34) {
                player.rideHorse = 1;
                player.xichtho_thienlyma = 2;
                player.idImgHorse = 1;
                player.maxhp += 1000;
                player.maxmp += 1000;
                player.speed = 6;
            } else if (type == 64) {
                player.rideHorse = 3;
            } else if (type == 65) {
                player.rideHorse = 4;
            } else if (type == 66) {
                player.rideHorse = 5;
            } else if (type == 67) {
                player.rideHorse = 6;
            } else if (type == 68) {
                player.rideHorse = 7;
            } else if (type == 86) {
                player.rideHorse = 8;
            } else if (type == 36) {
                player.rideHorse = 8;
            }

            if (type != 30) {
                player.calculateAttrib();
                player.speed = 6;
            }

            try {
                player.sendMessage(MessageCreator.createMainCharInfoMessage(player));
                player.sendToNearPlayer(MessageCreator.createCharInfo(player));
                player.sendMessage(MessageCreator.createCharInventoryMessage(player, 0));
                MessageCreator.createMsgCharMonster(player, player);
            } catch (Exception var5) {
            }
        } else {
            try {
                player.sendMessage(MessageCreator.createServerAlertMessage("Không thể dùng khi đang cưỡi ngựa", ""));
                player.potions[type]++;
                player.sendMessage(MessageCreator.createCharInventoryMessage(player, 0));
            } catch (Exception var4) {
            }
        }
    }

