    public void doAcceptChallengeParty(Char player, int ok) {
        try {
            Char p = CharManager.instance.getCharByCharName(player.nameCompetitor);
            if (p != null) {
                if (ok == 0) {
                    p.nameCompetitor = "";
                    p.moneyThachdau = 0;
                    p.sendMessage(MessageCreator.createServerAlertMessage(player.charname + " không chấp nhận lời thách đấu của bạn", ""));
                    return;
                }

                for (int i = 0; i < p.party.userParty.size(); i++) {
                    ((Char) p.party.userParty.get(i))
                            .sendMessage(
                                    MessageCreator.createServerAlertMessage(
                                            player.charname
                                            + " đã chấp nhận lời thách đấu nhóm của bạn. Trận đấu của nhóm bạn và nhóm "
                                            + player.nameCompetitor
                                            + " sẽ diễn ra sau 30s nữa.",
                                            ""
                                    )
                            );
                }

                for (int i = 0; i < player.party.userParty.size(); i++) {
                    ((Char) player.party.userParty.get(i))
                            .sendMessage(
                                    MessageCreator.createServerAlertMessage(
                                            "Bạn đã chấp nhận lời thách đấu của nhóm "
                                            + p.charname
                                            + ". Trận đấu của nhóm bạn và nhóm "
                                            + p.nameCompetitor
                                            + " sẽ diễn ra sau 30s nữa.",
                                            ""
                                    )
                            );
                }

                TeamArena team1 = new TeamArena(TeamArena.genIDTeam());
                TeamArena team2 = new TeamArena(TeamArena.genIDTeam());
                ArenaMap mm = (ArenaMap) RealController.mapList.get(205);
                ArenaData arena = new ArenaData();
                arena.addTeam(team1);
                arena.addTeam(team2);
                arena.idArena = IDARENA;
                arena.typeArena = 4;
                arena.start();
                mm.doAddArena(arena);
                p.idArena = IDARENA;
                player.idArena = IDARENA;
                arena.moneyThachdau = p.moneyThachdau * 2;
                arena.moneyThachdau = arena.moneyThachdau - arena.moneyThachdau / 5;
                p.subXu((long) p.moneyThachdau, false, "map 32");
                player.subXu((long) p.moneyThachdau, false, "map 33");
                team1.addMember(p);
                team2.addMember(player);
                Message m = null;
                m = new Message(65);
                m.dos.writeShort(p.id);
                p.pk = 14;
                m.dos.writeByte(1);
                m.dos.writeByte(14);
                p.timeUsePK = System.currentTimeMillis();
                p.sendMessage(m);
                p.sendToNearPlayer(m);

                for (int i = 0; i < p.party.userParty.size(); i++) {
                    Char pp = (Char) p.party.userParty.get(i);
                    if (pp.id != p.id) {
                        m = new Message(65);
                        m.dos.writeShort(pp.id);
                        pp.pk = 14;
                        m.dos.writeByte(1);
                        m.dos.writeByte(14);
                        pp.timeUsePK = System.currentTimeMillis();
                        pp.sendMessage(m);
                        pp.sendToNearPlayer(m);
                        pp.idArena = IDARENA;
                        team1.addMember(pp);
                    }
                }

                for (int ix = 0; ix < player.party.userParty.size(); ix++) {
                    Char pp = (Char) player.party.userParty.get(ix);
                    if (pp.id != player.id) {
                        m = new Message(65);
                        m.dos.writeShort(pp.id);
                        pp.pk = 15;
                        m.dos.writeByte(1);
                        m.dos.writeByte(15);
                        pp.timeUsePK = System.currentTimeMillis();
                        pp.sendMessage(m);
                        pp.sendToNearPlayer(m);
                        pp.idArena = IDARENA;
                        team2.addMember(pp);
                    }
                }

                m = new Message(65);
                m.dos.writeShort(player.id);
                player.pk = 15;
                m.dos.writeByte(1);
                m.dos.writeByte(15);
                player.timeUsePK = System.currentTimeMillis();
                player.sendMessage(m);
                player.sendToNearPlayer(m);
                arena.sendInfoMatch = true;
                arena.timeWaitFight = System.currentTimeMillis() + 30000L;
                IDARENA = (IDARENA + 1) % 2000000000;
                player.nameCompetitor = "";
                p.nameCompetitor = "";
                p.moneyThachdau = 0;
                player.moneyThachdau = 0;
            } else {
                player.sendMessage(MessageCreator.createServerAlertMessage(player.nameCompetitor + " đã thoát khỏi game", ""));
            }
        } catch (Exception var11) {
            var11.printStackTrace();
        }
    }

    private boolean doSetTitleClan(Char pMaster, Char player, boolean ordained) {
        try {
            NewClan clandata = NewClan.getClan(player.idClan);
            if (clandata.rankClan >= 3) {
                if (player.rankClan >= clandata.rankClan && !ordained) {
                    System.out.println("KHONG THE GIANG CHUC TU CHUC NHO XUONG CHUC LON HON");
                    return false;
                }

                NewClan.setRankClan(player.charname, clandata.rankClan, player.idClan);
                clandata.downRankMem(player.charname, clandata.rankClan);
                clandata.rankClan = 3;
                player.sendMessage(MessageCreator.createMainCharInfoMessage(player));
                player.sendMessage(MessageCreator.createCharInfo(player));
                return true;
            }

            if (clandata.rankClan == 0) {
                System.out.println("KHONG THE PHONG BANG CHU");
                return false;
            }

            if (player.rankClan <= clandata.rankClan && ordained) {
                System.out.println("KHONG THE PHONG CHUC TU CHUC LON XUONG CHUC NHO HON");
                return false;
            }

            if (player.rankClan >= clandata.rankClan && !ordained) {
                System.out.println("KHONG THE GIANG CHUC TU CHUC NHO XUONG CHUC LON HON");
                return false;
            }

            if (!ordained) {
                if (clandata.rankClan == 2 && NewClan.isEnoughtSubLeader(player.idClan, clandata.rankClan)) {
                    pMaster.sendMessage(MessageCreator.createServerAlertMessage("Bang chỉ có thể có tối đa 7 trưởng lão.", ""));
                    return false;
                }

                NewClan.setRankClan(player.charname, clandata.rankClan, player.idClan);
                clandata.downRankMem(player.charname, clandata.rankClan);
                clandata.rankClan = 3;
                player.sendMessage(MessageCreator.createMainCharInfoMessage(player));
                player.sendMessage(MessageCreator.createCharInfo(player));
                return true;
            }

            if (!NewClan.isEnoughtSubLeader(player.idClan, clandata.rankClan)) {
                NewClan.setRankClan(player.charname, clandata.rankClan, player.idClan);
                clandata.setRankMem(player.charname, clandata.rankClan);
                clandata.rankClan = 3;
                player.sendMessage(MessageCreator.createMainCharInfoMessage(player));
                player.sendMessage(MessageCreator.createCharInfo(player));
                MessageCreator.createMsgCharMonster(player, player);
                return true;
            }

            if (clandata.rankClan == 1) {
                pMaster.sendMessage(MessageCreator.createServerAlertMessage("Bang chỉ có thể có tối đa 2 phó bang.", ""));
            } else if (clandata.rankClan == 2) {
                pMaster.sendMessage(MessageCreator.createServerAlertMessage("Bang chỉ có thể có tối đa 7 trưởng lão.", ""));
            }
        } catch (Exception var5) {
            var5.printStackTrace();
        }

        return false;
    }

