    private void doKickParty(Char player, Message m) {
        try {
            byte value = m.dis.readByte();
            if (value == 0) {
                player.kickOutParty(m);
                return;
            }

            if (value == 1) {
                player.deleteParty();
                return;
            }

            if (value == 2) {
                player.outParty();
            }
        } catch (Exception var4) {
        }
    }

    private void doParty(Char player, Message message) {
        try {
            byte value = message.dis.readByte();
            if (value == 0) {
                player.sendInviteParty2User(message);
                return;
            }

            if (value == 1) {
                player.okJoinParty(message);
                return;
            }

            if (value == 2) {
                player.cancelJoinParty(message);
                return;
            }

            if (value == 3) {
                System.out.println("MOI BAN VAO TIEC");
                if (player.idWedding == -1) {
                    player.sendMessage(MessageCreator.createServerAlertMessage("Bạn không thể mời", ""));
                    return;
                }

                Wedding wd = (Wedding) allWedding.get(player.idWedding);
                if (wd == null) {
                    player.idWedding = -1;
                    return;
                }

                if (wd != null) {
                    if (wd.idP1 != player.charDBID && wd.idP2 != player.charDBID) {
                        player.sendMessage(MessageCreator.createServerAlertMessage("Bạn không thể mời", ""));
                        return;
                    }

                    if (player.potions[92] <= 0) {
                        player.sendMessage(MessageCreator.createServerAlertMessage("Bạn đã hết thiệp mời.", ""));
                        return;
                    }
                }

                short userId = message.dis.readShort();
                Char p = player.getCharFromNearChar(userId);
                if (p == null) {
                    return;
                }

                if (p.myCountry != player.myCountry) {
                    player.sendMessage(MessageCreator.createServerAlertMessage("Chỉ thể mới khách cũng lãnh thổ với bạn", ""));
                    return;
                }

                if (p.lvDetail.lv < 40) {
                    player.sendMessage(MessageCreator.createServerAlertMessage("Chỉ có thể mời người từ cấp độ 40 trở lên", ""));
                    return;
                }

                if (p.idWedding <= -1 && p.potions[92] <= 0) {
                    p.pInviteWedding = player.charname;
                    p.sendMessage(MessageCreator.createMsgPopUp(p.id, 7, "Bạn có đồng ý tham gia tiệc cưới của " + player.charname + " không?"));
                    return;
                }

                player.sendMessage(MessageCreator.createServerAlertMessage(p.charname + " đã nhận lời tham gia tiệc cưới của người khác.", ""));
                return;
            }
        } catch (Exception var7) {
            var7.printStackTrace();
        }
    }

    private void doSetTaxTown(Char player, Message message) {
        try {
            if (player.myCountry == -1) {
                return;
            }

            if (idClanTown[player.myCountry] == -1) {
                return;
            }

            if (idClanTown[player.myCountry] == player.idClan && player.inCountry != player.myCountry) {
                return;
            }

            if (player.myCountry != player.inCountry) {
                return;
            }

            byte tax = message.dis.readByte();
            if (tax < 0 || tax > 30) {
                player.sendMessage(MessageCreator.createServerAlertMessage("Chỉ có thể đặt thuế tối đa là 30%", ""));
                return;
            }

            NewClan clanInfo = getClaninfoByID(player.idClan);
            if (player.idClan == -1 || clanInfo == null || clanInfo != null && !clanInfo.master.toLowerCase().equals(player.charname.toLowerCase())) {
                player.sendMessage(MessageCreator.createServerAlertMessage("Chỉ có bang chủ mới có thể đặt thuế.", ""));
                return;
            }

            if (player.idClan != -1 && player.idClan != idClanTown[player.myCountry]) {
                player.sendMessage(MessageCreator.createServerAlertMessage("Chỉ có bang đang sở hữu thành mới được đặt thuế.", ""));
                return;
            }

            taxOfClan[player.myCountry] = tax;
            Database.instance.saveOrtherLog("", player.charname, clanInfo.name + "_" + clanInfo.master + "_" + tax + "_" + player.myCountry, "settax");
        } catch (Exception var5) {
        }
    }

