    private Item getItemEggByTemplate(final Char player, final int idTemplate) {
        for (int i = 0; i < player.iItems.size(); i++) {
            final Item item = (Item) player.iItems.elementAt(i);
            if (item != null && item.getTemplate().id == idTemplate) {
                return item;
            }
        }
        return null;
    }

    private boolean consumePotionOrItemEgg(final Char player, final int potionType, final int itemTemplate) {
        if (player.potions[potionType] > 0) {
            player.potions[potionType]--;
            return true;
        }

        final Item egg = this.getItemEggByTemplate(player, itemTemplate);
        if (egg == null) {
            return false;
        }

        player.iItems.remove(egg);
        player.removeIDItem(egg.id);
        player.sendMessage(MessageCreator.createCharInventoryMessage(player, 1));
        Database.instance.saveOrtherLog("", player.charname, "ap trung item " + egg.getName(), "trunglt");
        return true;
    }

    private boolean doUseSpecialAnimalEggItem(final Char player, final Item item) {
        if (item == null) {
            return false;
        }

        switch (item.getTemplate().id) {
            case ITEM_EGG_HOA_KY_LAN:
                player.iItems.remove(item);
                player.removeIDItem(item.id);
                player.sendMessage(MessageCreator.createCharInventoryMessage(player, 1));
                this.doCreateHoaKyLan(player);
                Database.instance.saveOrtherLog("", player.charname, "dung " + item.getName(), "trunglt");
                return true;
            case ITEM_EGG_DUONG_KHANG:
                this.doCreateAnimalFromItemEgg(player, item, "Đương khang", Animal.HEO);
                return true;
            case ITEM_EGG_LAN_SU_TU:
                this.doCreateAnimalFromItemEgg(player, item, "Lân sư tử", Animal.LAN);
                return true;
            case ITEM_EGG_BACH_COT:
                this.doCreateAnimalFromItemEgg(player, item, "Bạch cốt", Animal.NGUA_XUONG);
                return true;
            case ITEM_EGG_RONG_BANG:
                this.doCreateAnimalFromItemEgg(player, item, "Rồng Băng", Animal.RONG_LON);
                return true;
            default:
                return false;
        }
    }

    private void doCreateAnimalFromItemEgg(final Char player, final Item egg, final String name, final byte idImg) {
        player.iItems.remove(egg);
        player.removeIDItem(egg.id);
        player.sendMessage(MessageCreator.createCharInventoryMessage(player, 1));

        final Animal anima = new Animal();
        anima.createAtt();
        anima.name = name;
        anima.idImg = idImg;
        anima.level = 1;
        anima.place = 0;
        anima.ownerId = player.charDBID;
        anima.id = player.getIDItem();
        player.animal.add(anima);
        player.sendMessage(MessageCreator.createCharInventoryMessage(player, 0));
        player.sendMessage(MessageCreator.createCharInventoryMessage(player, 2));
        Database.instance.saveAnimal(anima);
        Database.instance.saveOrtherLog("tob_log_other_animal", player.charname, "Tao " + anima.name + " bang " + egg.getName() + " | " + anima.getAttribute(), "crt");
        player.sendMessage(MessageCreator.createServerAlertMessage("Chúc mừng. Bạn đã tạo được linh thú " + anima.name, ""));
    }



