    public static String getDotNumber(long m) {
        String str = "" + m;
        int len = str.length() / 3;
        if (str.length() % 3 == 0) {
            len--;
        }

        for (int i = 0; i < len; i++) {
            int index = str.length() - (i + 1) * 3 - i;
            str = str.substring(0, index) + "." + str.substring(index, str.length());
        }

        return str;
    }

