    private void doQuayso(Char player, int option) {
        try {
            if (option == 0) {
                int moneyQuay = 500;
                if (player.getxu() > (long) moneyQuay) {
                    player.subXu((long) moneyQuay, true, "map 85");
                    int random = new Random().nextInt(3);
                    switch (random) {
                        case 0:
                            player.sendItem(5, 0);
                            break;
                        case 1:
                            player.sendItem(5, 1);
                            break;
                        case 2:
                            player.sendItem(5, 2);
                    }
                } else {
                    player.sendMessage(MessageCreator.createServerAlertMessage("Không đủ xu", ""));
                }
            }

            if (option == 1) {
                int moneyQuay = 50;
                if (player.getLuong() > moneyQuay) {
                    player.subLuong((long) moneyQuay);
                    int random = new Random().nextInt(3);
                    switch (random) {
                        case 0:
                            player.sendItem(4, 0);
                            break;
                        case 1:
                            player.sendItem(4, 1);
                            break;
                        case 2:
                            player.sendItem(4, 2);
                    }
                } else {
                    player.sendMessage(MessageCreator.createServerAlertMessage("Không đủ lượng", ""));
                }
            }
        } catch (Exception var5) {
            var5.printStackTrace();
        }
    }

