    public static void selectionSort(Vector<CharInfo> top) {
        int n = top.size();

        for (int j = 0; j < n - 1; j++) {
            int iMin = j;
            CharInfo c1 = (CharInfo) top.get(j);

            for (int i = j + 1; i < n; i++) {
                CharInfo c2 = (CharInfo) top.get(i);
                if (c2.pk > c1.pk) {
                    iMin = i;
                }
            }

            if (iMin != j) {
                CharInfo c2 = (CharInfo) top.get(j);
                CharInfo c3 = (CharInfo) top.get(iMin);
                top.set(iMin, c2);
                top.set(j, c3);
            }
        }
    }

